use std::collections::VecDeque;

struct TokenStreamProcessor {
    tokens: VecDeque<u32>,
}

impl TokenStreamProcessor {
    fn new(initial_data: &[u32]) -> Self {
        let mut deque = VecDeque::from(initial_data.to_vec());
        TokenStreamProcessor { tokens: deque }
    }

    fn peek_and_process(&mut self) -> Option<u32> {
        if let Some(peeked_token) = self.tokens.front() {
            println!("Peeked token value: {}", peeked_token);
            return Some(*peeked_token);
        }
        None
    }

    fn consume_and_process(&mut self) -> Option<u32> {
        let consumed_token = self.tokens.pop_front();
        if let Some(token) = consumed_token {
            println!("Consumed token value: {}", token);
        }
        consumed_token
    }

    fn process_all(&mut self) -> Vec<u32> {
        let mut results = Vec::new();
        while let Some(token) = self.peek_and_process() {
            results.push(token);
            self.consume_and_process();
        }
        results
    }
}

fn main() {
    let input_tokens = vec![10, 25, 30, 41];
    let mut processor = TokenStreamProcessor::new(&input_tokens);

    println!("--- Initial Peek Check ---");
    processor.peek_and_process();

    println!("n--- Processing All Tokens (Peek/Consume Cycle) ---");
    let processed = processor.process_all();
    println!("Successfully processed tokens list: {:?}", processed);
}

use std::collections::HashMap;

struct CssPropertySorter {
    properties: HashMap<String, Vec<String>>,
}

impl CssPropertySorter {
    fn new() -> Self {
        CssPropertySorter { properties: HashMap::new() }
    }

    fn add_declaration(&mut self, property: &str, value: &str) {
        self.properties.entry(property.to_string()).or_insert_with(Vec::new).push(value.to_string());
    }

    fn get_sorted_declarations(&self) -> Vec<String> {
        let mut sorted_keys: Vec<&String> = self.properties.keys().collect();
        sorted_keys.sort_by(|a, b| a.cmp(b));

        let mut output = Vec::new();
        for key in sorted_keys {
            output.push(format!("{}: {}", key, self.properties[key].join(", ")))
        }
        output
    }
}

