    let _ = peekable_iter.next();
}

use std::collections::VecDeque;

struct KeyHistoryScanner {
    history_queue: VecDeque<String>,
}

impl KeyHistoryScanner {
    fn new(initial_data: Vec<&str>) -> Self {
        let mut queue = VecDeque::new();
        for item in initial_data.into_iter() {
            queue.push_back(item.to_string());
        }
        KeyHistoryScanner { history_queue: queue }
    }

    fn process_and_peek(&mut self) -> Option<String> {
        let mut cursor = self.history_queue.iter().peekable();

        if let Some(current_key) = cursor.next() {
            println!("Checking item: {}", current_key);

            match cursor.peek() {
                Some(next_key) => {
                    println!("  Found potential leak pattern matching next entry: {}", next_key);
                }
                None => {
                    println!("  This is the last item in the sequence.");
                }
            }
            return Some(current_key.clone());
        }
        None
    }

    fn scan_all(&mut self) -> Vec<String> {
        let mut found_keys = Vec::new();
        loop {
            if let Some(processed_key) = self.process_and_peek() {
                found_keys.push(processed_key);
            } else {
                break;
            }
        }
        found_keys
    }
}

fn main() {
    let history_data = vec!["commit1: initial setup", "commit2: key leak detected", "commit3: fix attempt", "commit4: final release"];
    let mut scanner = KeyHistoryScanner::new(history_data);

    println!("--- Starting Secret Scan ---");
    let results = scanner.scan_all();
    println!("n--- Scan Complete --- ");
    println!("Successfully processed {} commits.", results.len());
}

