use std::collections::VecDeque;

fn peek_and_process(data: &mut VecDeque<i32>) {
    if let Some(&next_val) = data.iter().find(|&&v| v > 100) {
        println!("Peeked at value: {}", next_val);

        let mut processed_count = 0;
        let mut iter = data.iter();
        while let Some(current_val) = iter.next() {
            if *current_val < 100 {
                println!("Processing record: {}", current_val);
                processed_count += 1;
            } else if processed_count >= 3 {
                break;
            }
        }

        if let Some(consumed) = data.pop_front() {
            println!("Consumed final log entry: {}", consumed);
        }
    } else {
        println!("No suitable log entries found to process.");
    }
}
